const rows = items.map(i=>i.json);
const now = new Date();
const hhmm = now.toTimeString().slice(0,5);
if (!(hhmm >= '06:00' && hhmm <= '21:00')) return [{ json: { mode:'outside_window' } }];

const sd = this.getWorkflowStaticData('global');
const today = now.toISOString().slice(0,10);
if (sd.sendDate !== today){ sd.sendDate = today; sd.sentToday = 0; }
const cap = Number($node['Config – Sender'].json.dailySendCap || 40);
if ((sd.sentToday || 0) >= cap) return [{ json: { mode:'cap_reached', sentToday: sd.sentToday, cap } }];

for (let i=0;i<rows.length;i++){
  const r = rows[i];
  const status = (r.Status||'').toString().toLowerCase();
  const approved = (r['ApprovedToSend (Y/N)']||'').toString().toUpperCase();
  const method = (r['Contact Method']||'Email').toString();
  const email = (r['Contact Email']||'').toString();
  if (status === 'queued' && approved === 'Y' && method === 'Email' && email){
    return [{ json: { mode:'send', rowNumber: i+2, row: r } }];
  }
}
return [{ json: { mode:'none' } }];

function norm(s){ return (s ?? '').toString().trim(); }
function daysBetween(a,b){ return Math.floor((a-b)/(24*3600*1000)); }
const today = new Date();
const rows = items.map(i=>i.json);
const noResponse=[],interestedNoMeeting=[],timingLater=[];
for(let idx=0;idx<rows.length;idx++){
  const r=rows[idx], rowNumber=idx+2;
  const status=norm(r.Status).toLowerCase();
  const lastTouch=norm(r['Last Touch Date']);
  const meeting=norm(r['Meeting Date/Time']);
  const outcome=norm(r['Outcome Reason']).toLowerCase();
  if(outcome.includes('timing')||outcome.includes('later'))
    timingLater.push({rowNumber,name:r['Business Name']||r.BusinessName});
  if(status.includes('interested')&&!meeting)
    interestedNoMeeting.push({rowNumber,name:r['Business Name']||r.BusinessName});
  if(status==='sent'&&lastTouch){
    const lt=new Date(lastTouch);
    if(!isNaN(lt)&&daysBetween(today,lt)>=3)
      noResponse.push({rowNumber,name:r['Business Name']||r.BusinessName,types:r['Type(s)']||r.Types||''});
  }
}
return [{json:{noResponse,interestedNoMeeting,timingLater}}];

const arr=($json.interestedNoMeeting||[]).slice(0,12);
if(!arr.length) return [{json:{skip:true}}];
const lines=arr.map(x=>`\u2022 ${x.name} (row ${x.rowNumber})`).join('\n');
return [{json:{text:'INTERESTED - NO MEETING - CALL TODAY:\n'+lines}}];

const arr=($json.noResponse||[]).slice(0,12);
if(!arr.length) return [{json:{skip:true}}];
const lines=arr.map(x=>`\u2022 ${x.name} (row ${x.rowNumber})`).join('\n');
return [{json:{text:'NO RESPONSE (3+ days):\n'+lines}}];

const arr=($json.timingLater||[]).slice(0,12);
if(!arr.length) return [{json:{skip:true}}];
const lines=arr.map(x=>`\u2022 ${x.name} (row ${x.rowNumber})`).join('\n');
return [{json:{text:'TIMING/LATER - re-engage soon:\n'+lines}}];

const text=($json.message?.text||'').trim();
const lower=text.toLowerCase();
let cmd='help',payload='';
if(lower.startsWith('/today')) cmd='today';
else if(lower.startsWith('/due')) cmd='due';
else if(lower.startsWith('/top10')) cmd='top10';
else if(lower.startsWith('/addportfolio')){cmd='addportfolio';payload=text.replace(/\/addportfolio\s*/i,'');}
return [{json:{cmd,payload,chatId:$json.message.chat.id}}];

const cmd=$node['Parse Command'].json.cmd;
const chatId=$node['Parse Command'].json.chatId;
const rows=items.map(i=>i.json);
const today=new Date().toISOString().slice(0,10);
let text='';
if(cmd==='today'){
  const sent=rows.filter(r=>(r['Sent Date']||'')===today);
  const queued=rows.filter(r=>(r.Status||'').toLowerCase()==='queued');
  text='TODAY ('+today+'):\nSent: '+sent.length+'\nQueued: '+queued.length+'\nTotal: '+rows.length;
}else if(cmd==='due'){
  const due=rows.filter(r=>(r['Next Follow-up Date']||'')<=today&&!['closed','unsubscribed'].includes((r.Status||'').toLowerCase()));
  const lines=due.slice(0,15).map(r=>'- '+(r['Business Name']||'?')+' ('+(r.Status||'?')+')').join('\n');
  text='FOLLOW-UPS DUE ('+due.length+'):\n'+(lines||'None!');
}else if(cmd==='top10'){
  const scored=rows.filter(r=>r['Lead Score']).sort((a,b)=>Number(b['Lead Score'])-Number(a['Lead Score'])).slice(0,10);
  const lines=scored.map((r,i)=>(i+1)+'. '+(r['Business Name']||'?')+' Score:'+(r['Lead Score']||'')).join('\n');
  text='TOP 10 LEADS:\n'+(lines||'No scored leads.');
}
return [{json:{chatId,text}}];
